// ---------------------------------------------------------------------------
// Mongoose Schemas
// ---------------------------------------------------------------------------
const CategorySchema = new mongoose.Schema(
  {
    title: { type: String, required: true, unique: true },
    slug: { type: String, required: true, unique: true, index: true },
    description: { type: String, default: "" },
    image: { type: String, default: "" },
    isActive: { type: Boolean, default: true, index: true },
  },
  { timestamps: true }
);

const QuestionSchema = new mongoose.Schema(
  {
    question: { type: String, required: true, trim: true },
    options: {
      type: [{ type: String, required: true }],
      required: true,
      validate: {
        validator: (arr) => Array.isArray(arr) && arr.length === 4,
        message: "Options must contain exactly 4 values",
      },
    },
    correctAnswer: { type: Number, required: true, min: 0, max: 3 },
    category: {
      type: mongoose.Schema.Types.ObjectId,
      ref: "Category",
      required: true,
      index: true,
    },
    difficulty: {
      type: String,
      enum: ["easy", "medium", "hard"],
      default: "easy",
    },
    isActive: { type: Boolean, default: true, index: true },
  },
  { timestamps: true }
);

QuestionSchema.index({ category: 1, createdAt: -1 });

const Category = mongoose.models.Category || mongoose.model("Category", CategorySchema);
const Question = mongoose.models.Question || mongoose.model("Question", QuestionSchema);

// ---------------------------------------------------------------------------
// Seed function
// ---------------------------------------------------------------------------
async function seed() {
  await mongoose.connect(MONGO_URI, { bufferCommands: false });

  await Promise.all([Question.deleteMany({}), Category.deleteMany({})]);
  console.log("🧹 Cleared existing categories and questions");

  const categoryMap = new Map();

  for (const category of categoriesSeed) {
    const slug = toSlug(category.title);
    const savedCategory = await Category.create({
      title: category.title,
      slug,
      description: category.description,
      image: "",
      isActive: true,
    });

    categoryMap.set(category.title, savedCategory._id);
    console.log(`✔ Category: ${category.title} (${savedCategory._id})`);
  }

  let inserted = 0;

  for (const category of categoriesSeed) {
    const categoryId = categoryMap.get(category.title);
    const questions = questionsData[category.title] || [];

    if (questions.length > 0) {
      await Question.insertMany(
        questions.map((q) => ({
          ...q,
          category: categoryId,
          isActive: true,
        }))
      );
      inserted += questions.length;
    }

    console.log(`  ↳ ${questions.length} questions seeded for "${category.title}"`);
  }

  const [categoryCount, questionCount] = await Promise.all([
    Category.countDocuments({}),
    Question.countDocuments({}),
  ]);

  console.log("\n🎉 Quiz seed completed");
  console.log(`   Categories inserted  : ${categoriesSeed.length}`);
  console.log(`   Questions inserted   : ${inserted}`);
  console.log(`   Total categories DB  : ${categoryCount}`);
  console.log(`   Total questions DB   : ${questionCount}`);

  await mongoose.disconnect();
}

seed().catch(async (error) => {
  console.error(error);
  await mongoose.disconnect();
  process.exit(1);
});
